-- Update Auto-Thread web-admin description to list supported links (incl. fx/vx Twitter fixers).
INSERT INTO module_links_pics_vids_autothread(key,value) VALUES('editorConfig','{"title":"Auto-Thread","description":"Auto-creates a comments thread on qualifying posts in watched channels. Supported: X/Twitter (+ fxtwitter, fixupx, twittpr, vxtwitter, fixvx), Bluesky, Aethy, Instagram; Discord images/videos.","fields":[{"key":"channelIds","label":"Watched channels","type":"channel-multi","store":"config","help":"Channels where the bot auto-creates a comments thread on qualifying posts."},{"key":"deleteNonQualifyingMessages","label":"Delete non-qualifying posts","type":"boolean","store":"config","help":"When on, messages without images, videos, or supported post links are deleted and the author receives a DM asking them to use comments threads."},{"key":"threadFirstMessage","label":"Thread opener","type":"textarea","help":"First message posted in the auto-created comments thread."},{"key":"nonQualifyingDm","label":"Non-qualifying post DM","type":"textarea","help":"Sent privately when a non-qualifying post is deleted. Tokens: {channel} (clickable channel link), {message}. Text over 2000 characters is sent as an embed automatically."}]}') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
